class Solution {
    public int clumsy(int n) {
        int res = n;
        n--;
        boolean sign = true;
        while (n > 0) {
            if (sign) {
                if (n > 1) {
                    res = res * n;
                    n--;
                    res = res / n;
                    n--;
                } else {
                    res = res * n;
                    n--;
                }
            } else {
                if (n > 1) {
                    res = res + n;
                    n--;
                    res = res - (n);
                    n--;
                } else {
                    res = res + n;
                    n--;
                }
            }
            sign = !sign;
        }
        return res;
    }
}
